}
function tableAll(){
  const m=S.month,pm=prevM(m),ym=yoyM(m),q=S.kq.toLowerCase();
  let rows=KWS.filter(e=>inUni(e)&&e.series[m]).map(e=>{const s=e.series[m],sp=pm&&e.series[pm],sy=ym&&e.series[ym];
    return {kw:e.kw,cls:e.cls,sv:s.sv,od:s.od,bi:s.bi,bc:s.bc,ba:s.ba,bo:s.bo,ao:s.ao==null?null:s.ao,
      mom:sp?s.bo-sp.bo:null,yoy:sy?s.bo-sy.bo:null,gap:s.ao==null?s.bo:s.bo-s.ao};});
  if(S.kfilter==='core')rows=rows.filter(r=>r.cls==='core'); if(S.kfilter==='mic')rows=rows.filter(r=>r.cls!=='core');
  if(q)rows=rows.filter(r=>r.kw.toLowerCase().includes(q));
  rows.sort((a,b)=>{let x=a[S.sortKey],y=b[S.sortKey];if(x==null)x=-1e9;if(y==null)y=-1e9;return S.sortAsc?x-y:y-x;});
  el('rowCount').textContent=rows.length+' 词'+(rows.length>300?' (前300)':'');
  const cols=[['kw','关键词',r=>esc(r.kw)+kcls(r)],['sv','搜索量',r=>fmtInt(r.sv)],['od','大盘成交',r=>fmtInt(r.od)],
    ['bi','曝光份额',r=>pct(r.bi)],['bc','点击份额',r=>pct(r.bc)],['ba','加购份额',r=>pct(r.ba)],['bo','购买份额',r=>'<b>'+pct(r.bo)+'</b>'],
    ['mom','份额环比',r=>dc(r.mom)],['yoy','份额同比',r=>dc(r.yoy)],['ao','ASIN购买份额',r=>r.ao==null?'—':pct(r.ao)],['gap','品牌−ASIN',r=>pct(r.gap)]];
  el('t-all').innerHTML='<thead><tr>'+cols.map(c=>`<th data-k="${c[0]}">${c[1]}</th>`).join('')+'</tr></thead><tbody>'+
    rows.slice(0,300).map(r=>'<tr>'+cols.map(c=>`<td>${c[2](r)}</td>`).join('')+'</tr>').join('')+'</tbody>';
  el('t-all').querySelectorAll('th').forEach(th=>th.onclick=()=>{const k=th.dataset.k;if(S.sortKey===k)S.sortAsc=!S.sortAsc;else{S.sortKey=k;S.sortAsc=false;}tableAll();});
}
const dc=d=>d==null?'<span class=muted>—</span>':`<span class="${d>0?'num-pos':d<0?'num-neg':'muted'}">${(d>=0?'+':'')+d.toFixed(2)}pp</span>`;
/* ===== 解读卡渲染 ===== */
function tagCls(t){return /数据/.test(t)?'data':'exp';}
function tagTxt(t){return /数据/.test(t)?'数据支撑':'专家建议';}
function actsHtml(acts){return acts.map(a=>`<div class="act"><span class="tag ${tagCls(a.tag)}">${tagTxt(a.tag)}</span><span>${inl(a.text)}</span></div>`).join('');}
function renderInsight(node,mod,withDetail=true){
  const o=INSIGHTS[mod]; if(!o){node.innerHTML='<span class="muted">(解读生成中)</span>';return;}
  let h=`<h3>${esc(o.title||'')}</h3><div class="card">${inl(o.card||'')}</div>`;
  if(o.actions)h+=`<div class="acts">${actsHtml(o.actions)}</div>`;
  if(withDetail&&o.detail)h+=`<details class="expander"><summary>展开详情</summary><div class="mdbox">${md(o.detail)}</div></details>`;
  node.innerHTML=h;
}
function renderQ6(){
  const o=INSIGHTS.Q6; if(!o){el('ins-Q6-card').innerHTML='<span class=muted>(生成中)</span>';return;}
  el('ins-Q6-card').innerHTML=`<h3>${esc(o.title||'')}</h3><div class="card">${inl(o.card||'')}</div>`;
  el('playbook').innerHTML=`<div class="pb"><h4><span class="dot" style="background:var(--brand)"></span><span class="site-on">站内打法</span></h4>${actsHtml(o.actions_onsite||[])}</div>
    <div class="pb"><h4><span class="dot" style="background:var(--asin)"></span><span class="site-off">站外打法</span></h4>${actsHtml(o.actions_offsite||[])}</div>`;
  el('q6detail').innerHTML=md(o.detail||'');
}
/* ===== 控件 & 初始化 ===== */
function rerenderAll(){renderKPI();renderCharts();boardsQ5();tableAll();}
function initInsights(){['Q1','Q2','Q3','Q4','Q5'].forEach(q=>renderInsight(el('ins-'+q),q));renderQ6();}
function initFoot(){el('foot').innerHTML=`<b>口径与局限</b> ① 份额=品牌/ASIN捕获量÷各阶段<b>大盘量</b>;搜索量=市场需求规模,非份额分母。② 核心整机=含karaoke词根(含错拼、singing machine/ktv)剔麦克风配件;宽口径=全部卡拉OK词根。③ 数据为每月Top1000(品牌)/Top100(ASIN)搜索词,头部截断非全量;逐词表保留峰值搜索量Top1500。④ <b>年对年</b>轴:实线=2026、虚线=2025;同比仅2026-02~06有2025对照月(缺2025-01)。⑤ 解读中<span class="tag data" style="font-size:10px">数据支撑</span>=数据直接支持,<span class="tag exp" style="font-size:10px">专家建议</span>=经验判断,需实测验证。⑥ 12月为圣诞季峰值,解读趋势注意季节性。⑦ 总量/份额指标以<b>聚合口径</b>(每月全部核心词)为准;逐词表为按峰值搜索量的 Top1500 精简子集,勿用逐词求和反推大盘/品牌总量。⑧ "份额两环打平"(如加购份额=购买份额)表示该环<b>转化与大盘同速</b>,不代表零流失——品牌加购→成交约30%、约七成加购未成交。<br>数据来源:亚马逊美国站 品牌分析·搜索查询绩效(SQP),2025-02~2026-06。`;}
function init(){
  el('rng').textContent=M[0]+' ~ '+M[M.length-1]+'('+M.length+'个月)';
  const sm=el('selMonth');sm.innerHTML=M.map(m=>`<option${m===S.month?' selected':''}>${m}</option>`).join('');
  sm.onchange=e=>{S.month=e.target.value;rerenderAll();};
  el('segUni').querySelectorAll('button').forEach(b=>b.onclick=()=>{S.uni=b.dataset.v;el('segUni').querySelectorAll('button').forEach(x=>x.classList.toggle('on',x===b));rerenderAll();});
  el('segAxis').querySelectorAll('button').forEach(b=>b.onclick=()=>{S.axis=b.dataset.v;el('segAxis').querySelectorAll('button').forEach(x=>x.classList.toggle('on',x===b));renderCharts();});
  el('q3stage').onchange=e=>{S.q3stage=e.target.value;renderCharts();};
  el('kwSearch').oninput=e=>{S.kq=e.target.value;tableAll();};
  document.querySelectorAll('.filters .pill').forEach(p=>p.onclick=()=>{S.kfilter=p.dataset.f;document.querySelectorAll('.filters .pill').forEach(x=>x.classList.toggle('on',x===p));tableAll();});
  initInsights();initFoot();rerenderAll();
}
init();
</script>
</body>
</html>

