1	<!DOCTYPE html>
2	<html lang="zh-CN">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=1480">
6	<title>Ikarao · 卡拉OK市场 增长仪表盘 V2</title>
7	<style>
8	  :root{
9	    --bg:#eef1f5; --panel:#fff; --ink:#18202e; --muted:#5b6675; --line:#e3e8ef; --line2:#eef2f7;
10	    --brand:#2f6df6; --asin:#e8730c; --mkt:#8a94a6;
11	    --imp:#7aa5ff; --clk:#2f6df6; --atc:#7b5cf0; --ord:#0f9d76;
12	    --good:#0f9d76; --bad:#e0483d; --warn:#e8730c;
13	    --chip:#eef2f8; --data:#e8f0ff; --data-ink:#2f6df6; --exp:#fff2e2; --exp-ink:#c9691a;
14	    --shadow:0 1px 3px rgba(20,30,50,.08),0 1px 2px rgba(20,30,50,.04);
15	  }
16	  *{box-sizing:border-box}
17	  body{margin:0;background:var(--bg);color:var(--ink);font-size:14px;line-height:1.55;
18	    font-family:"Segoe UI",-apple-system,"Microsoft YaHei","PingFang SC",Roboto,Arial,sans-serif;-webkit-font-smoothing:antialiased}
19	  .wrap{width:1440px;margin:0 auto;padding:20px 24px 70px}
20	  h1,h2,h3,h4{margin:0;font-weight:700}
21	  .muted{color:var(--muted)}
22	  header.top{display:flex;align-items:flex-end;justify-content:space-between;gap:20px;
23	    padding:18px 22px;background:linear-gradient(120deg,#22335a,#33527f);color:#fff;border-radius:12px;box-shadow:var(--shadow)}
24	  header.top h1{font-size:21px}
25	  header.top .sub{font-size:13px;opacity:.86;margin-top:4px}
26	  .controls{display:flex;gap:14px;align-items:flex-end;flex-wrap:wrap}
27	  .ctl{display:flex;flex-direction:column;gap:4px}
28	  .ctl label{font-size:12px;opacity:.85}
29	  select{font-size:14px;padding:6px 10px;border-radius:8px;border:1px solid #ffffff44;background:#fff;color:var(--ink);min-width:110px}
30	  .seg{display:inline-flex;background:#ffffff22;border-radius:8px;padding:3px;gap:2px}
31	  .seg button{font-size:13px;padding:6px 12px;border:0;background:transparent;color:#fff;border-radius:6px;cursor:pointer;opacity:.8}
32	  .seg button.on{background:#fff;color:var(--ink);opacity:1;font-weight:600}
33	  /* nav */
34	  nav.q{display:flex;gap:8px;margin-top:14px;flex-wrap:wrap}
35	  nav.q a{font-size:12.5px;color:var(--muted);text-decoration:none;background:#fff;border:1px solid var(--line);
36	    padding:6px 12px;border-radius:20px}
37	  nav.q a:hover{border-color:var(--brand);color:var(--brand)}
38	  /* KPI */
39	  .kpis{display:grid;grid-template-columns:repeat(6,1fr);gap:14px;margin-top:16px}
40	  .kpi{background:var(--panel);border:1px solid var(--line);border-radius:12px;box-shadow:var(--shadow);padding:13px 15px}
41	  .kpi .lab{font-size:12px;color:var(--muted);display:flex;align-items:center;gap:6px}
42	  .kpi .val{font-size:23px;font-weight:800;margin-top:5px}
43	  .kpi .val .u{font-size:13px;font-weight:600;color:var(--muted)}
44	  .kpi .sub{font-size:12px;color:var(--muted);margin-top:3px}
45	  .kpi .row{display:flex;gap:8px;margin-top:8px;flex-wrap:wrap}
46	  .badge{display:inline-flex;align-items:center;gap:2px;font-size:11.5px;font-weight:700;padding:2px 6px;border-radius:20px;background:var(--chip)}
47	  .badge.up{color:var(--good);background:#e6f6f0}.badge.down{color:var(--bad);background:#fdecea}.badge.flat{color:var(--muted)}
48	  .badge .lb{font-weight:600;color:var(--muted);font-size:10.5px}
49	  .dot{width:9px;height:9px;border-radius:2px;display:inline-block}
50	  /* module */
51	  section.mod{margin-top:22px;background:var(--panel);border:1px solid var(--line);border-radius:14px;box-shadow:var(--shadow);overflow:hidden}
52	  .mhead{padding:14px 20px;border-bottom:1px solid var(--line2);display:flex;align-items:baseline;gap:12px}
53	  .mhead .q{font-size:12px;font-weight:800;color:#fff;background:var(--brand);border-radius:6px;padding:3px 9px}
54	  .mhead h2{font-size:16.5px}
55	  .mhead .qhint{font-size:12.5px;color:var(--muted)}
56	  .mbody{padding:16px 20px;display:grid;gap:18px}
57	  .m2{grid-template-columns:1.35fr 1fr}
58	  .chart-card .chart-head{display:flex;justify-content:space-between;align-items:center;margin-bottom:4px}
59	  .chart-card h3{font-size:14px}
60	  .legend{display:flex;gap:12px;flex-wrap:wrap;font-size:12px}
61	  .legend .li{display:flex;align-items:center;gap:5px}
62	  .legend .ln{width:16px;height:0;border-top-width:2.5px;border-top-style:solid;display:inline-block}
63	  svg .grid line{stroke:var(--line2)} svg .axis text{fill:var(--muted);font-size:11px}
64	  svg .ln{fill:none;stroke-width:2.2} svg .pt{stroke:#fff;stroke-width:1.3}
65	  svg .selm{stroke:#c9d2e0;stroke-width:1;stroke-dasharray:4 3}
66	  svg .bar{rx:2}
67	  .tip{position:fixed;pointer-events:none;background:#1c2740;color:#fff;font-size:12px;padding:8px 10px;border-radius:8px;
68	    box-shadow:0 6px 20px rgba(0,0,0,.25);z-index:60;opacity:0;transition:opacity .08s;max-width:280px}
69	  .tip .tl{display:flex;justify-content:space-between;gap:14px}
70	  /* insight card */
71	  .insight{background:#fafcff;border:1px solid var(--line);border-radius:12px;padding:14px 16px}
72	  .insight h3{font-size:14px;margin-bottom:6px}
73	  .insight .card{font-size:13.5px;line-height:1.7}
74	  .acts{margin-top:12px;display:flex;flex-direction:column;gap:8px}
75	  .act{font-size:13px;line-height:1.6;display:flex;gap:8px;align-items:flex-start}
76	  .tag{flex:none;font-size:10.5px;font-weight:800;padding:2px 7px;border-radius:5px;margin-top:2px}
77	  .tag.data{background:var(--data);color:var(--data-ink)} .tag.exp{background:var(--exp);color:var(--exp-ink)}
78	  .expander{margin-top:12px;border-top:1px dashed var(--line);padding-top:10px}
79	  .expander>summary{cursor:pointer;font-size:12.5px;color:var(--brand);font-weight:600;list-style:none;user-select:none}
80	  .expander>summary::-webkit-details-marker{display:none}
81	  .expander>summary::before{content:"▸ ";}
82	  .expander[open]>summary::before{content:"▾ ";}
83	  .mdbox{font-size:13px;line-height:1.7;margin-top:8px}
84	  .mdbox h4{font-size:13.5px;margin:12px 0 5px} .mdbox h5{font-size:13px;margin:10px 0 4px;color:var(--muted)}
85	  .mdbox p{margin:6px 0} .mdbox ul{margin:6px 0;padding-left:20px} .mdbox li{margin:3px 0}
