</html>
'''

HTML = HTML.replace('__Q1DATA__', json.dumps(Q1, ensure_ascii=False, separators=(',',':')))
io.open(OUT,'w',encoding='utf-8').write(HTML)
print('written', OUT, 'bytes', os.path.getsize(OUT))

